input.command:
log show --last 2h | grep "Previous shutdown cause" || true; 
sysctl kern.last_shutdown_reason || true;
ls -F /Library/Logs/DiagnosticReports/ | grep -E "Kernel|panic" || true;
nvram -p | grep panic || true

ls -lt /Library/Logs/DiagnosticReports/ | grep -E "panic|Kernel" | head -n 20;
log show --last 1h --predicate 'process == "watchdogd" OR eventMessage CONTAINS "thermal" OR eventMessage CONTAINS "GPU"' --style syslog | head -n 100;
sysctl -a | grep -E "thermal|temperature" || true
